using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents and direct SQL queries still work.
            b.HasDiscriminator<string>("Discriminator").HasValue<Product>("Product");

            // EF9 removed the discriminator prefix from the JSON id property
            // (was "Product|123", now "123"). Preserve the old format for existing data.
            b.HasDiscriminatorInJsonId();

            // EF9 maps the key property directly to the JSON "id" field, removing the
            // separate "Id" JSON property. Keep the shadow id so the document shape
            // matches what EF8 wrote (both "id" and "Id" present).
            b.HasShadowId();

            // HasIndex is removed — Cosmos indexes all properties by default and
            // EF9 now throws instead of silently ignoring the call.
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

