        // EF9: SQL queries must project with VALUE (SELECT VALUE c, not SELECT *)
        // c.Discriminator still works because we configured HasDiscriminator("Discriminator")
        var sql = "SELECT VALUE c FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

